33:	);
35:	const { data: modelTokensData } = useAnalyticsQuery(
36:		orpc.analytics.overview.modelTokensTrend.queryOptions({
37:			input: { days },
38:		}),
39:	);
41:	const { data: insights } = useAnalyticsQuery(
42:		orpc.analytics.overview.insights.queryOptions({ input: { days } }),
43:	);
45:	const hasData = !kpisLoading && kpis && kpis.distinct_sessions > 0;
47:	return (
48:		<div className="px-8 py-6">
49:			<PageHeader
50:				title="Dashboard Overview"
51:				description="Track your team's Claude Code usage and metrics"
52:				actions={
53:					hasData ? (
54:						<DatePicker
55:							startDate={startDate}
56:							endDate={endDate}
57:							onStartDateChange={setStartDate}
58:							onEndDateChange={setEndDate}
59:						/>
60:					) : undefined
61:				}
62:			/>
64:			{kpisLoading && (
65:				<div className="flex items-center justify-center py-12">
66:					<div className="text-center">
67:						<Spinner size="lg" className="mb-4" />
68:						<p className="text-muted">Loading dashboard data...</p>
69:					</div>
70:				</div>
71:			)}
73:			{!kpisLoading && kpis && kpis.distinct_sessions === 0 && <CliSetupHint />}
75:			{hasData && (
76:				<>
77:					<div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8">
78:						<StatCard
79:							title="Distinct Users"
80:							value={kpis.distinct_users.toLocaleString()}
81:							icon={Users}
82:							iconColor="text-green-600"
83:							href="/dashboard/developers"
84:							linkLabel="Go to users"
85:						/>
86:						<StatCard
87:							title="Distinct Sessions"
88:							value={kpis.distinct_sessions.toLocaleString()}
89:							icon={Activity}
90:							iconColor="text-blue-600"
91:							href="/dashboard/sessions"
92:							linkLabel="Go to sessions"
93:						/>
94:						<StatCard
95:							title="Distinct Projects"
96:							value={kpis.distinct_projects.toLocaleString()}
97:							icon={FolderKanban}
98:							iconColor="text-purple-600"
99:							href="/dashboard/projects"
100:							linkLabel="Go to projects"
101:						/>
102:						<StatCard
103:							title="Distinct Subagents"
104:							value={kpis.distinct_subagents.toLocaleString()}
105:							icon={Bot}
106:							iconColor="text-orange-600"
107:							href="/dashboard/sessions"
108:							linkLabel="Go to sessions"
109:						/>
110:						<StatCard
111:							title="Slash Commands"
112:							value={kpis.distinct_slash_commands.toLocaleString()}
113:							icon={Terminal}
114:							iconColor="text-cyan-600"
115:							href="/dashboard/sessions"
116:							linkLabel="Go to sessions"
117:						/>
118:						<StatCard
119:							title="Distinct Skills"
120:							value={kpis.distinct_skills.toLocaleString()}
121:							icon={Sparkles}
122:							iconColor="text-pink-600"
123:							href="/dashboard/sessions"
124:							linkLabel="Go to sessions"
125:						/>
126:					</div>
128:					{insights && insights.length > 0 && (
129:						<div className="mb-8">
130:							<h2 className="text-xl font-bold text-heading mb-4">
131:								Quick Insights
132:							</h2>
133:							<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
134:								{insights.map((insight, index) => (
135:									<InsightCard
136:										// biome-ignore lint/suspicious/noArrayIndexKey: static insights list
137:										key={index}
138:										insight={{
139:											type: insight.type as
140:												| "trend"
141:												| "performer"
142:												| "alert"
143:												| "info",
144:											severity: insight.severity,
145:											message: insight.message,
146:											link: insight.link || "/dashboard",
147:										}}
148:									/>
149:								))}
150:							</div>
151:						</div>
152:					)}
154:					{usageTrendData && usageTrendData.length > 0 && (
155:						<AnalyticsCard className="mb-8">
156:							<h2 className="text-xl font-bold text-heading mb-4">
157:								Usage Trends
158:							</h2>
159:							<p className="text-sm text-muted mb-6">
160:								Track key metrics over time - switch between metric pairs to see
161:								different views
162:							</p>
163:							<UsageTrendChart
164:								data={usageTrendData}
165:								showRollingAverage={false}
166:							/>
167:						</AnalyticsCard>
168:					)}
170:					{modelTokensData && modelTokensData.length > 0 && (
171:						<AnalyticsCard className="mb-8">
172:							<h2 className="text-xl font-bold text-heading mb-4">
173:								Tokens by Model
174:							</h2>
175:							<p className="text-sm text-muted mb-6">
176:								Token consumption broken down by model type over time
177:							</p>
178:							<ModelTokensChart data={modelTokensData} />
179:						</AnalyticsCard>
180:					)}
181:				</>
182:			)}
183:		</div>
184:	);
185:}

1:import { os } from "../../middleware.js";
2:import { developersRouter } from "./developers.js";
