	.use(orgMiddleware)
	.handler(async ({ input, context }) => {
		return getOverviewKPIs(context.organizationId, input.days);
	});

const usageTrend = os.analytics.overview.usageTrend
	.use(orgMiddleware)
	.handler(async ({ input, context }) => {
		return getUsageTrendDetailed(context.organizationId, input.days);
